int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::string c;
    std::cin >> n >> c;
    std::string keys = "ABXY";
    std::vector<std::string> cmd;
    for (char x : keys) {
        for (char y : keys) cmd.push_back(std::string({x, y}));
    }

    int best = n;
    for (const std::string& l : cmd) {
        for (const std::string& r : cmd) {
            int press = 0;
            for (int i = 0; i < n;) {
