int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n, l;
    std::cin >> n >> l;
    std::string line;
    std::getline(std::cin, line);
    std::vector<std::string> rows(l);
    for (int i = 0; i < l; ++i) std::getline(std::cin, rows[i]);
    std::string bottom;
    std::getline(std::cin, bottom);

    int pos = 0;
    for (int i = 0; i < static_cast<int>(bottom.size()); ++i) {
        if (bottom[i] == 'o') pos = i / 2;
    }
    for (int r = l - 1; r >= 0; --r) {
        int idx = pos * 2;
        if (idx - 1 >= 0 && rows[r][idx - 1] == '-') --pos;
        else if (idx + 1 < static_cast<int>(rows[r].size()) && rows[r][idx + 1] == '-') ++pos;
    }
    std::cout << pos + 1 << '\n';
    return 0;
}

