struct Number {
    std::string original;
    std::string converted;
};

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    std::vector<int> rank(10);
    for (int i = 0; i < 10; ++i) {
        int d;
        std::cin >> d;
        rank[d] = i;
    }
    int n;
    std::cin >> n;
    std::vector<Number> nums(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> nums[i].original;
        for (char ch : nums[i].original) nums[i].converted.push_back(static_cast<char>('0' + rank[ch - '0']));
    }
    std::sort(nums.begin(), nums.end(), [](const Number& a, const Number& b) {
        if (a.converted.size() != b.converted.size()) return a.converted.size() < b.converted.size();
        return a.converted < b.converted;
    });
    for (const auto& num : nums) std::cout << num.original << '\n';
    return 0;
}

