int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::cin >> n;
    std::vector<int> t(n);
    int total = 0;
    for (int& x : t) {
        std::cin >> x;
        total += x;
    }
    int ans = total;
    for (int mask = 0; mask < (1 << n); ++mask) {
        int s = 0;
        for (int i = 0; i < n; ++i) if ((mask >> i) & 1) s += t[i];
        ans = std::min(ans, std::max(s, total - s));
    }
    std::cout << ans << '\n';
    return 0;
}

