long long digit_sum(long long x) {
    long long s = 0;
    while (x > 0) {
        s += x % 10;
        x /= 10;
    }
    return s;
}

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    long long n;
    std::cin >> n;
    std::vector<long long> ans;
    for (long long x = std::max(1LL, n - 200); x <= n; ++x) {
        if (x + digit_sum(x) == n) ans.push_back(x);
    }
    std::cout << ans.size() << '\n';
    for (long long x : ans) std::cout << x << '\n';
    return 0;
}

