#include <iostream>

long long dist2(long long x1, long long y1, long long x2, long long y2) {
    long long dx = x1 - x2;
    long long dy = y1 - y2;
    return dx * dx + dy * dy;
}

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    long long x, y, r, x2, y2, x3, y3;
    std::cin >> x >> y >> r >> x2 >> y2 >> x3 >> y3;
    bool circle_in_rect = (x - r >= x2 && x + r <= x3 && y - r >= y2 && y + r <= y3);
    bool rect_in_circle = true;
    long long rr = r * r;
    rect_in_circle &= dist2(x, y, x2, y2) <= rr;
    rect_in_circle &= dist2(x, y, x2, y3) <= rr;
    rect_in_circle &= dist2(x, y, x3, y2) <= rr;
    rect_in_circle &= dist2(x, y, x3, y3) <= rr;
    std::cout << (circle_in_rect ? "NO" : "YES") << '\n';
    std::cout << (rect_in_circle ? "NO" : "YES") << '\n';
    return 0;
}

